// ============================================================
// UzMAX MOVE CONTROLLER v4 - ESP32
// Hold-to-move dashboard control for 2 stepper motors.
//
// Dashboard protocol:
//   PING              -> DEVICE:MOVE
//   MOVE SPEED 60     -> speed 0..100
//   MOVE FWD          -> start moving forward
//   MOVE BACK         -> start moving backward
//   MOVE LEFT         -> pivot/turn left
//   MOVE RIGHT        -> pivot/turn right
//   MOVE PING         -> keepalive while button/key is held
//   MOVE STOP         -> stop when button/key is released
//
// Also supports test commands:
//   left_fwd, left_back, right_fwd, right_back
//   robot_fwd, robot_back, spin_cw, spin_ccw, demo, stop
// ============================================================

#include <Arduino.h>

#define DEVICE_NAME "MOVE"

#define LEFT_STEP_PIN   18
#define LEFT_DIR_PIN    19
#define LEFT_EN_PIN     21

#define RIGHT_STEP_PIN  22
#define RIGHT_DIR_PIN   23
#define RIGHT_EN_PIN    25

#define DRIVER_ENABLE_LEVEL  LOW
#define DRIVER_DISABLE_LEVEL HIGH

// Speed is pulse delay in microseconds: lower = faster.
#define PULSE_SLOW          3000
#define PULSE_FAST           300
#define ACCEL_STEPS          250
#define DECEL_STEPS          120
#define SERIAL_CHECK_STEPS    10
#define KEEPALIVE_TIMEOUT_MS 350

String queuedCommand = "";
volatile bool stopRequested = false;
bool motorRunning = false;
int currentSpeed = 60;
unsigned long lastKeepAlive = 0;

int speedToPulseDelay(int speed) {
  speed = constrain(speed, 0, 100);
  return map(speed, 0, 100, PULSE_SLOW, PULSE_FAST);
}

float smoothStep(float t) {
  t = constrain(t, 0.0f, 1.0f);
  return t * t * (3.0f - 2.0f * t);
}

int rampDelay(int stepIndex, int targetDelay) {
  if (stepIndex >= ACCEL_STEPS) return targetDelay;
  float t = smoothStep((float)stepIndex / ACCEL_STEPS);
  return (int)(PULSE_SLOW - t * (PULSE_SLOW - targetDelay));
}

int stopDelay(int stepIndex, int startDelay) {
  if (stepIndex >= DECEL_STEPS) return PULSE_SLOW;
  float t = smoothStep((float)stepIndex / DECEL_STEPS);
  return (int)(startDelay + t * (PULSE_SLOW - startDelay));
}

void enableLeftDriver() {
  digitalWrite(LEFT_EN_PIN, DRIVER_ENABLE_LEVEL);
}

void disableLeftDriver() {
  digitalWrite(LEFT_EN_PIN, DRIVER_DISABLE_LEVEL);
}

void enableRightDriver() {
  digitalWrite(RIGHT_EN_PIN, DRIVER_ENABLE_LEVEL);
}

void disableRightDriver() {
  digitalWrite(RIGHT_EN_PIN, DRIVER_DISABLE_LEVEL);
}

void enableAllDrivers() {
  enableLeftDriver();
  enableRightDriver();
}

void disableAllDrivers() {
  disableLeftDriver();
  disableRightDriver();
}

void pulsePin(int stepPin, int delayUs) {
  digitalWrite(stepPin, HIGH);
  delayMicroseconds(delayUs);
  digitalWrite(stepPin, LOW);
  delayMicroseconds(delayUs);
}

void pulseBoth(int delayUs) {
  digitalWrite(RIGHT_STEP_PIN, HIGH);
  digitalWrite(LEFT_STEP_PIN, HIGH);
  delayMicroseconds(delayUs);
  digitalWrite(RIGHT_STEP_PIN, LOW);
  digitalWrite(LEFT_STEP_PIN, LOW);
  delayMicroseconds(delayUs);
}

void applyBothDirection(bool leftForward, bool rightForward) {
  // Direction mapping follows your corrected test code.
  digitalWrite(RIGHT_DIR_PIN, leftForward ? HIGH : LOW);
  digitalWrite(LEFT_DIR_PIN, rightForward ? HIGH : LOW);
}

void checkSerial() {
  if (motorRunning && millis() - lastKeepAlive > KEEPALIVE_TIMEOUT_MS) {
    stopRequested = true;
    return;
  }

  if (!Serial.available()) return;

  String incoming = Serial.readStringUntil('\n');
  incoming.trim();
  incoming.toUpperCase();
  if (incoming.length() == 0) return;

  if (incoming == "PING") {
    Serial.println("DEVICE:MOVE");
    return;
  }

  if (incoming == "MOVE PING") {
    lastKeepAlive = millis();
    return;
  }

  if (incoming.startsWith("MOVE SPEED ")) {
    currentSpeed = constrain(incoming.substring(11).toInt(), 0, 100);
    Serial.print("OK:SPEED ");
    Serial.println(currentSpeed);
    return;
  }

  if (incoming == "MOVE STOP" || incoming == "STOP") {
    stopRequested = true;
    return;
  }

  queuedCommand = incoming;
  stopRequested = true;
}

void continuousBoth(bool leftForward, bool rightForward) {
  enableAllDrivers();
  applyBothDirection(leftForward, rightForward);

  motorRunning = true;
  stopRequested = false;
  lastKeepAlive = millis();

  int accelStep = 0;
  int decelStep = 0;
  int serialStep = 0;
  int currentDelay = PULSE_SLOW;
  bool decelerating = false;

  while (true) {
    int targetDelay = speedToPulseDelay(currentSpeed);

    if (!decelerating) {
      currentDelay = rampDelay(accelStep++, targetDelay);
    }

    if (stopRequested) decelerating = true;

    if (decelerating) {
      currentDelay = stopDelay(decelStep++, currentDelay);
      if (decelStep >= DECEL_STEPS) break;
    }

    pulseBoth(currentDelay);

    if (++serialStep >= SERIAL_CHECK_STEPS) {
      serialStep = 0;
      checkSerial();
    }
  }

  motorRunning = false;
  disableAllDrivers();
  Serial.println("OK:STOP");
}

void continuousSingle(int stepPin, int dirPin, int enPin, bool dir) {
  digitalWrite(enPin, DRIVER_ENABLE_LEVEL);
  digitalWrite(dirPin, dir ? HIGH : LOW);

  motorRunning = true;
  stopRequested = false;
  lastKeepAlive = millis();

  int accelStep = 0;
  int decelStep = 0;
  int serialStep = 0;
  int currentDelay = PULSE_SLOW;
  bool decelerating = false;

  while (true) {
    int targetDelay = speedToPulseDelay(currentSpeed);

    if (!decelerating) {
      currentDelay = rampDelay(accelStep++, targetDelay);
    }

    if (stopRequested) decelerating = true;

    if (decelerating) {
      currentDelay = stopDelay(decelStep++, currentDelay);
      if (decelStep >= DECEL_STEPS) break;
    }

    pulsePin(stepPin, currentDelay);

    if (++serialStep >= SERIAL_CHECK_STEPS) {
      serialStep = 0;
      checkSerial();
    }
  }

  motorRunning = false;
  disableAllDrivers();
  Serial.println("OK:STOP");
}

void fixedSingle(int stepPin, int dirPin, int enPin, bool dir, int steps, int pulseDelay) {
  digitalWrite(enPin, DRIVER_ENABLE_LEVEL);
  digitalWrite(dirPin, dir ? HIGH : LOW);
  for (int i = 0; i < steps; i++) {
    pulsePin(stepPin, pulseDelay);
  }
  disableAllDrivers();
}

void fixedBoth(bool leftForward, bool rightForward, int steps, int pulseDelay) {
  enableAllDrivers();
  applyBothDirection(leftForward, rightForward);
  for (int i = 0; i < steps; i++) {
    pulseBoth(pulseDelay);
  }
  disableAllDrivers();
}

void runDemo() {
  Serial.println("DEMO:START");
  fixedSingle(RIGHT_STEP_PIN, RIGHT_DIR_PIN, RIGHT_EN_PIN, true, 1000, 700);
  delay(300);
  fixedSingle(RIGHT_STEP_PIN, RIGHT_DIR_PIN, RIGHT_EN_PIN, false, 1000, 700);
  delay(300);
  fixedSingle(LEFT_STEP_PIN, LEFT_DIR_PIN, LEFT_EN_PIN, false, 1000, 700);
  delay(300);
  fixedSingle(LEFT_STEP_PIN, LEFT_DIR_PIN, LEFT_EN_PIN, true, 1000, 700);
  delay(300);
  fixedBoth(true, false, 1400, 700);
  delay(300);
  fixedBoth(false, true, 1400, 700);
  delay(300);
  fixedBoth(true, true, 1400, 700);
  delay(300);
  fixedBoth(false, false, 1400, 700);
  Serial.println("DEMO:END");
}

String parseMoveDirection(String input) {
  if (input == "W" || input == "ROBOT_FWD") return "FWD";
  if (input == "S" || input == "ROBOT_BACK") return "BACK";
  if (input == "A") return "LEFT";
  if (input == "D") return "RIGHT";
  if (input == "SPIN_CW") return "CW";
  if (input == "SPIN_CCW") return "CCW";

  if (input.startsWith("MOVE ")) {
    String rest = input.substring(5);
    int firstSpace = rest.indexOf(' ');
    return firstSpace < 0 ? rest : rest.substring(0, firstSpace);
  }

  return "";
}

void handleCommand(String input) {
  input.trim();
  input.toUpperCase();
  if (input.length() == 0) return;

  if (input == "PING") {
    Serial.println("DEVICE:MOVE");
    return;
  }

  if (input == "MOVE PING") {
    lastKeepAlive = millis();
    return;
  }

  if (input == "MOVE STOP" || input == "STOP") {
    stopRequested = true;
    motorRunning = false;
    disableAllDrivers();
    Serial.println("OK:STOP");
    return;
  }

  if (input.startsWith("MOVE SPEED ")) {
    currentSpeed = constrain(input.substring(11).toInt(), 0, 100);
    Serial.print("OK:SPEED ");
    Serial.println(currentSpeed);
    return;
  }

  if (input == "LEFT_FWD") {
    fixedSingle(RIGHT_STEP_PIN, RIGHT_DIR_PIN, RIGHT_EN_PIN, true, 1000, 700);
    Serial.println("OK:LEFT_FWD");
    return;
  }
  if (input == "LEFT_BACK") {
    fixedSingle(RIGHT_STEP_PIN, RIGHT_DIR_PIN, RIGHT_EN_PIN, false, 1000, 700);
    Serial.println("OK:LEFT_BACK");
    return;
  }
  if (input == "RIGHT_FWD") {
    fixedSingle(LEFT_STEP_PIN, LEFT_DIR_PIN, LEFT_EN_PIN, false, 1000, 700);
    Serial.println("OK:RIGHT_FWD");
    return;
  }
  if (input == "RIGHT_BACK") {
    fixedSingle(LEFT_STEP_PIN, LEFT_DIR_PIN, LEFT_EN_PIN, true, 1000, 700);
    Serial.println("OK:RIGHT_BACK");
    return;
  }
  if (input == "DEMO") {
    runDemo();
    return;
  }

  String direction = parseMoveDirection(input);
  if (direction.length() == 0) {
    Serial.println("ERR:UNKNOWN");
    return;
  }

  stopRequested = false;
  lastKeepAlive = millis();

  if (direction == "FWD") {
    Serial.println("OK:MOVE_FWD");
    continuousBoth(false, true);
  } else if (direction == "BACK") {
    Serial.println("OK:MOVE_BACK");
    continuousBoth(true, false);
  } else if (direction == "LEFT") {
    Serial.println("OK:MOVE_LEFT");
    continuousSingle(RIGHT_STEP_PIN, RIGHT_DIR_PIN, RIGHT_EN_PIN, true);
  } else if (direction == "RIGHT") {
    Serial.println("OK:MOVE_RIGHT");
    continuousSingle(LEFT_STEP_PIN, LEFT_DIR_PIN, LEFT_EN_PIN, false);
  } else if (direction == "CW") {
    Serial.println("OK:MOVE_CW");
    continuousBoth(true, true);
  } else if (direction == "CCW") {
    Serial.println("OK:MOVE_CCW");
    continuousBoth(false, false);
  } else {
    Serial.println("ERR:UNKNOWN_DIR");
  }
}

void setup() {
  Serial.begin(115200);

  pinMode(LEFT_STEP_PIN, OUTPUT);
  pinMode(LEFT_DIR_PIN, OUTPUT);
  pinMode(LEFT_EN_PIN, OUTPUT);
  pinMode(RIGHT_STEP_PIN, OUTPUT);
  pinMode(RIGHT_DIR_PIN, OUTPUT);
  pinMode(RIGHT_EN_PIN, OUTPUT);

  digitalWrite(LEFT_STEP_PIN, LOW);
  digitalWrite(LEFT_DIR_PIN, LOW);
  digitalWrite(RIGHT_STEP_PIN, LOW);
  digitalWrite(RIGHT_DIR_PIN, LOW);

  disableAllDrivers();
  Serial.println("DEVICE:MOVE");
  Serial.println("MOVE VERSION 4 READY");
}

void loop() {
  if (queuedCommand.length() > 0) {
    String next = queuedCommand;
    queuedCommand = "";
    handleCommand(next);
    return;
  }

  if (!Serial.available()) return;

  String command = Serial.readStringUntil('\n');
  command.trim();
  handleCommand(command);
}

// ===== UzMAX MOVE CONTROLLER - ESP32 - KEYDOWN/KEYUP SUPPORT =====

#include <Arduino.h>

#define DEVICE_NAME "MOVE"

#define LEFT_STEP_PIN   18
#define LEFT_DIR_PIN    19
#define LEFT_EN_PIN     21

#define RIGHT_STEP_PIN  22
#define RIGHT_DIR_PIN   23
#define RIGHT_EN_PIN    25

#define DRIVER_ENABLE_LEVEL  LOW
#define DRIVER_DISABLE_LEVEL HIGH

#define PULSE_SLOW   3000
#define PULSE_FAST    300
#define ACCEL_STEPS   800
#define DECEL_STEPS   800

// If no keepalive received within this ms, auto-stop.
// Set to 0 to disable timeout and use explicit MOVE STOP only.
#define KEEPALIVE_TIMEOUT_MS  300

String cmd = "";
volatile bool stopRequested = false;
int currentSpeed = 60;
unsigned long lastKeepAlive = 0;
bool motorRunning = false;

int speedToPulseDelay(int speed) {
  speed = constrain(speed, 0, 100);
  return map(speed, 0, 100, PULSE_SLOW, PULSE_FAST);
}

void checkStop() {
  if (Serial.available()) {
    String incoming = Serial.readStringUntil('\n');
    incoming.trim();
    incoming.toUpperCase();

    if (incoming == "PING") {
      Serial.println("DEVICE:MOVE");
      return;
    }

    // Keepalive must be handled before generic MOVE command detection.
    if (incoming == "MOVE PING") {
      lastKeepAlive = millis();
      return;
    }

    if (incoming == "MOVE STOP" || incoming == "STOP") {
      stopRequested = true;
      return;
    }

    if (incoming.startsWith("MOVE ") || incoming == "W" ||
        incoming == "A" || incoming == "S" || incoming == "D") {
      stopRequested = true;
      cmd = incoming;
      return;
    }
  }

  if (KEEPALIVE_TIMEOUT_MS > 0 && motorRunning) {
    if (millis() - lastKeepAlive > KEEPALIVE_TIMEOUT_MS) {
      stopRequested = true;
    }
  }
}

void enableLeftDriver()   { digitalWrite(LEFT_EN_PIN,  DRIVER_ENABLE_LEVEL);  }
void disableLeftDriver()  { digitalWrite(LEFT_EN_PIN,  DRIVER_DISABLE_LEVEL); }
void enableRightDriver()  { digitalWrite(RIGHT_EN_PIN, DRIVER_ENABLE_LEVEL);  }
void disableRightDriver() { digitalWrite(RIGHT_EN_PIN, DRIVER_DISABLE_LEVEL); }
void enableAllDrivers()   { enableLeftDriver();  enableRightDriver();  }
void disableAllDrivers()  { disableLeftDriver(); disableRightDriver(); }

int getAccelDelay(int i, int totalSteps, int targetDelay) {
  if (totalSteps > 0 && totalSteps <= ACCEL_STEPS + DECEL_STEPS) return targetDelay;

  if (i < ACCEL_STEPS) {
    float t = (float)i / ACCEL_STEPS;
    float curve = t * t * (3.0f - 2.0f * t);
    return (int)(PULSE_SLOW - curve * (PULSE_SLOW - targetDelay));
  }

  if (totalSteps > 0 && i >= totalSteps - DECEL_STEPS) {
    float t = (float)(totalSteps - i) / DECEL_STEPS;
    float curve = t * t * (3.0f - 2.0f * t);
    return (int)(PULSE_SLOW - curve * (PULSE_SLOW - targetDelay));
  }

  return targetDelay;
}

void stepMotorAccel(int stepPin, int dirPin, bool dir, int steps, int targetDelay) {
  digitalWrite(dirPin, dir ? HIGH : LOW);

  for (int i = 0; i < steps; i++) {
    if (stopRequested) return;
    int d = getAccelDelay(i, steps, targetDelay);
    digitalWrite(stepPin, HIGH);
    delayMicroseconds(d);
    digitalWrite(stepPin, LOW);
    delayMicroseconds(d);
    if (i % 50 == 0) checkStop();
  }
}

void stepBothAccel(bool leftFwd, bool rightFwd, int steps, int targetDelay) {
  digitalWrite(RIGHT_DIR_PIN, leftFwd ? HIGH : LOW);
  digitalWrite(LEFT_DIR_PIN, rightFwd ? HIGH : LOW);

  for (int i = 0; i < steps; i++) {
    if (stopRequested) return;
    int d = getAccelDelay(i, steps, targetDelay);
    digitalWrite(RIGHT_STEP_PIN, HIGH);
    digitalWrite(LEFT_STEP_PIN, HIGH);
    delayMicroseconds(d);
    digitalWrite(RIGHT_STEP_PIN, LOW);
    digitalWrite(LEFT_STEP_PIN, LOW);
    delayMicroseconds(d);
    if (i % 50 == 0) checkStop();
  }
}

void continuousBoth(bool leftFwd, bool rightFwd, int targetDelay) {
  enableAllDrivers();
  motorRunning = true;
  lastKeepAlive = millis();

  digitalWrite(RIGHT_DIR_PIN, leftFwd ? HIGH : LOW);
  digitalWrite(LEFT_DIR_PIN, rightFwd ? HIGH : LOW);

  int currentDelay = PULSE_SLOW;
  int stepCount = 0;
  bool decelerating = false;
  int accelStep = 0;
  int decelStep = 0;

  while (true) {
    if (!decelerating && currentDelay > targetDelay) {
      accelStep++;
      float t = constrain((float)accelStep / ACCEL_STEPS, 0.0f, 1.0f);
      float curve = t * t * (3.0f - 2.0f * t);
      currentDelay = (int)(PULSE_SLOW - curve * (PULSE_SLOW - targetDelay));
      if (currentDelay < targetDelay) currentDelay = targetDelay;
    }

    if (stopRequested) decelerating = true;

    if (decelerating) {
      decelStep++;
      float t = constrain((float)decelStep / DECEL_STEPS, 0.0f, 1.0f);
      float curve = 1.0f - t * t * (3.0f - 2.0f * t);
      currentDelay = (int)(targetDelay + curve * (PULSE_SLOW - targetDelay));
      if (currentDelay >= PULSE_SLOW) break;
    }

    digitalWrite(RIGHT_STEP_PIN, HIGH);
    digitalWrite(LEFT_STEP_PIN, HIGH);
    delayMicroseconds(currentDelay);
    digitalWrite(RIGHT_STEP_PIN, LOW);
    digitalWrite(LEFT_STEP_PIN, LOW);
    delayMicroseconds(currentDelay);

    if (++stepCount >= 50) {
      stepCount = 0;
      checkStop();
    }
  }

  motorRunning = false;
  disableAllDrivers();
  Serial.println("OK:NO_RESPONSE");
}

void continuousSingle(int stepPin, int dirPin, bool dir, int targetDelay) {
  digitalWrite(dirPin, dir ? HIGH : LOW);
  motorRunning = true;
  lastKeepAlive = millis();

  int currentDelay = PULSE_SLOW;
  int stepCount = 0;
  bool decelerating = false;
  int accelStep = 0;
  int decelStep = 0;

  while (true) {
    if (!decelerating && currentDelay > targetDelay) {
      accelStep++;
      float t = constrain((float)accelStep / ACCEL_STEPS, 0.0f, 1.0f);
      float curve = t * t * (3.0f - 2.0f * t);
      currentDelay = (int)(PULSE_SLOW - curve * (PULSE_SLOW - targetDelay));
      if (currentDelay < targetDelay) currentDelay = targetDelay;
    }

    if (stopRequested) decelerating = true;

    if (decelerating) {
      decelStep++;
      float t = constrain((float)decelStep / DECEL_STEPS, 0.0f, 1.0f);
      float curve = 1.0f - t * t * (3.0f - 2.0f * t);
      currentDelay = (int)(targetDelay + curve * (PULSE_SLOW - targetDelay));
      if (currentDelay >= PULSE_SLOW) break;
    }

    digitalWrite(stepPin, HIGH);
    delayMicroseconds(currentDelay);
    digitalWrite(stepPin, LOW);
    delayMicroseconds(currentDelay);

    if (++stepCount >= 50) {
      stepCount = 0;
      checkStop();
    }
  }

  motorRunning = false;
  disableAllDrivers();
  Serial.println("OK:NO_RESPONSE");
}

void moveLogicalLeft(bool forward, int steps, int pulseDelay) {
  enableRightDriver();
  stepMotorAccel(RIGHT_STEP_PIN, RIGHT_DIR_PIN, forward, steps, pulseDelay);
}

void moveLogicalRight(bool forward, int steps, int pulseDelay) {
  enableLeftDriver();
  stepMotorAccel(LEFT_STEP_PIN, LEFT_DIR_PIN, !forward, steps, pulseDelay);
}

void moveBothLogical(bool leftFwd, bool rightFwd, int steps, int pulseDelay) {
  enableAllDrivers();
  stepBothAccel(leftFwd, rightFwd, steps, pulseDelay);
}

void handleMoveCommand(String input) {
  input.trim();
  input.toUpperCase();

  int pulseDelay = speedToPulseDelay(currentSpeed);
  stopRequested = false;

  if (input == "PING") {
    Serial.println("DEVICE:MOVE");
    return;
  }

  if (input == "MOVE STOP" || input == "STOP") {
    stopRequested = true;
    motorRunning = false;
    disableAllDrivers();
    Serial.println("OK:NO_RESPONSE");
    return;
  }

  if (input == "MOVE PING") {
    lastKeepAlive = millis();
    return;
  }

  if (input.startsWith("MOVE SPEED ")) {
    int val = input.substring(11).toInt();
    currentSpeed = constrain(val, 0, 100);
    Serial.print("OK:SPEED ");
    Serial.println(currentSpeed);
    return;
  }

  String dir = "";
  int steps = 0;

  if (input.startsWith("MOVE ")) {
    String rest = input.substring(5);
    int spaceIdx = rest.indexOf(' ');
    if (spaceIdx == -1) {
      dir = rest;
      steps = 0;
    } else {
      dir = rest.substring(0, spaceIdx);
      steps = rest.substring(spaceIdx + 1).toInt();
    }
  } else if (input == "W") {
    dir = "FWD";
  } else if (input == "S") {
    dir = "BACK";
  } else if (input == "A") {
    dir = "LEFT";
  } else if (input == "D") {
    dir = "RIGHT";
  } else {
    Serial.println("ERR:UNKNOWN");
    return;
  }

  if (dir == "FWD") {
    Serial.println(steps ? "MOVE FWD " + String(steps) : "MOVE FWD");
    if (steps) {
      moveBothLogical(true, false, steps, pulseDelay);
      disableAllDrivers();
    } else {
      continuousBoth(true, false, pulseDelay);
    }
  } else if (dir == "BACK") {
    Serial.println(steps ? "MOVE BACK " + String(steps) : "MOVE BACK");
    if (steps) {
      moveBothLogical(false, true, steps, pulseDelay);
      disableAllDrivers();
    } else {
      continuousBoth(false, true, pulseDelay);
    }
  } else if (dir == "LEFT") {
    Serial.println(steps ? "MOVE LEFT " + String(steps) : "MOVE LEFT");
    if (steps) {
      moveLogicalLeft(true, steps, pulseDelay);
      disableAllDrivers();
    } else {
      enableRightDriver();
      continuousSingle(RIGHT_STEP_PIN, RIGHT_DIR_PIN, true, pulseDelay);
    }
  } else if (dir == "RIGHT") {
    Serial.println(steps ? "MOVE RIGHT " + String(steps) : "MOVE RIGHT");
    if (steps) {
      moveLogicalRight(true, steps, pulseDelay);
      disableAllDrivers();
    } else {
      enableLeftDriver();
      continuousSingle(LEFT_STEP_PIN, LEFT_DIR_PIN, false, pulseDelay);
    }
  } else if (dir == "CW") {
    Serial.println(steps ? "MOVE CW " + String(steps) : "MOVE CW");
    if (steps) {
      moveBothLogical(true, true, steps, pulseDelay);
      disableAllDrivers();
    } else {
      continuousBoth(true, true, pulseDelay);
    }
  } else if (dir == "CCW") {
    Serial.println(steps ? "MOVE CCW " + String(steps) : "MOVE CCW");
    if (steps) {
      moveBothLogical(false, false, steps, pulseDelay);
      disableAllDrivers();
    } else {
      continuousBoth(false, false, pulseDelay);
    }
  } else {
    Serial.println("ERR:UNKNOWN_DIR");
  }

  if (stopRequested) {
    motorRunning = false;
    disableAllDrivers();
    Serial.println("OK:NO_RESPONSE");
    stopRequested = false;
  }
}

void setup() {
  Serial.begin(115200);

  pinMode(LEFT_STEP_PIN, OUTPUT);
  pinMode(LEFT_DIR_PIN, OUTPUT);
  pinMode(LEFT_EN_PIN, OUTPUT);
  pinMode(RIGHT_STEP_PIN, OUTPUT);
  pinMode(RIGHT_DIR_PIN, OUTPUT);
  pinMode(RIGHT_EN_PIN, OUTPUT);

  digitalWrite(LEFT_STEP_PIN, LOW);
  digitalWrite(LEFT_DIR_PIN, LOW);
  digitalWrite(RIGHT_STEP_PIN, LOW);
  digitalWrite(RIGHT_DIR_PIN, LOW);

  disableAllDrivers();
  Serial.println("DEVICE:MOVE");
  Serial.println("MOVE READY");
}

void loop() {
  if (cmd.length() > 0) {
    String queued = cmd;
    cmd = "";
    handleMoveCommand(queued);
    return;
  }

  if (Serial.available()) {
    cmd = Serial.readStringUntil('\n');
    cmd.trim();
    if (cmd.length() > 0) {
      handleMoveCommand(cmd);
      cmd = "";
    }
  }
}

// ============================================================
// UzMAX MOVE CONTROLLER - ESP32
// 30kg Robot | 1/8 Microstepping | S-Curve Accel | Keydown/Keyup
// ============================================================

#include <Arduino.h>

#define DEVICE_NAME "MOVE"

// Pin definitions
#define LEFT_STEP_PIN    18
#define LEFT_DIR_PIN     19
#define LEFT_EN_PIN      21
#define RIGHT_STEP_PIN   22
#define RIGHT_DIR_PIN    23
#define RIGHT_EN_PIN     25

#define ENABLE           LOW
#define DISABLE          HIGH

// Microstepping: 1/8. 200 steps/rev * 8 = 1600 steps/rev.
#define STEPS_PER_REV    1600

// Speed. Pulse delay in microseconds, lower = faster.
#define PULSE_START      4000
#define PULSE_SLOW       3000
#define PULSE_FAST        200

// Acceleration profile.
#define ACCEL_STEPS      1200
#define DECEL_STEPS      1200
#define DIAG_RATIO       0.65f

// Safety.
#define KEEPALIVE_MS      300
#define SERIAL_CHECK_INT   30

volatile bool stopRequested = false;
bool motorRunning = false;
int currentSpeed = 60;
unsigned long lastKeepAlive = 0;
String pendingCmd = "";
String cmd = "";

int speedToDelay(int speed) {
  speed = constrain(speed, 0, 100);
  return map(speed, 0, 100, PULSE_SLOW, PULSE_FAST);
}

float sCurve(float t) {
  t = constrain(t, 0.0f, 1.0f);
  return t * t * (3.0f - 2.0f * t);
}

int blendDelay(float t, int startDelay, int endDelay) {
  return (int)(startDelay + sCurve(t) * (endDelay - startDelay));
}

void enableL() {
  digitalWrite(LEFT_EN_PIN, ENABLE);
}

void enableR() {
  digitalWrite(RIGHT_EN_PIN, ENABLE);
}

void disableL() {
  digitalWrite(LEFT_EN_PIN, DISABLE);
}

void disableR() {
  digitalWrite(RIGHT_EN_PIN, DISABLE);
}

void enableAll() {
  enableL();
  enableR();
}

void stopAll() {
  disableL();
  disableR();
}

void checkSerial() {
  if (!Serial.available()) {
    if (motorRunning && millis() - lastKeepAlive > KEEPALIVE_MS) {
      stopRequested = true;
    }
    return;
  }

  String incoming = Serial.readStringUntil('\n');
  incoming.trim();
  incoming.toUpperCase();

  if (incoming == "PING") {
    Serial.println("DEVICE:MOVE");
    return;
  }

  if (incoming == "MOVE STOP" || incoming == "STOP") {
    stopRequested = true;
    return;
  }

  if (incoming == "MOVE PING") {
    lastKeepAlive = millis();
    return;
  }

  if (incoming.length() > 0) {
    pendingCmd = incoming;
    stopRequested = true;
  }
}

inline void pulsePin(int pin, int delayUs) {
  digitalWrite(pin, HIGH);
  delayMicroseconds(delayUs);
  digitalWrite(pin, LOW);
  delayMicroseconds(delayUs);
}

inline void pulseBoth(int delayUs) {
  digitalWrite(RIGHT_STEP_PIN, HIGH);
  digitalWrite(LEFT_STEP_PIN, HIGH);
  delayMicroseconds(delayUs);
  digitalWrite(RIGHT_STEP_PIN, LOW);
  digitalWrite(LEFT_STEP_PIN, LOW);
  delayMicroseconds(delayUs);
}

int fixedMoveDelay(int index, int totalSteps, int targetDelay) {
  if (totalSteps <= ACCEL_STEPS + DECEL_STEPS) return targetDelay;
  if (index < ACCEL_STEPS) {
    return blendDelay((float)index / ACCEL_STEPS, PULSE_START, targetDelay);
  }
  if (index >= totalSteps - DECEL_STEPS) {
    return blendDelay((float)(totalSteps - index) / DECEL_STEPS, PULSE_START, targetDelay);
  }
  return targetDelay;
}

void fixedBoth(bool leftFwd, bool rightFwd, int steps, int targetDelay) {
  enableAll();
  digitalWrite(RIGHT_DIR_PIN, leftFwd ? HIGH : LOW);
  digitalWrite(LEFT_DIR_PIN, rightFwd ? HIGH : LOW);

  for (int i = 0; i < steps; i++) {
    if (stopRequested) break;
    pulseBoth(fixedMoveDelay(i, steps, targetDelay));
    if (i % SERIAL_CHECK_INT == 0) checkSerial();
  }

  stopAll();
  Serial.println("OK:NO_RESPONSE");
}

void fixedSingle(int stepPin, int dirPin, bool dir, int steps, int targetDelay) {
  digitalWrite(dirPin, dir ? HIGH : LOW);

  for (int i = 0; i < steps; i++) {
    if (stopRequested) break;
    pulsePin(stepPin, fixedMoveDelay(i, steps, targetDelay));
    if (i % SERIAL_CHECK_INT == 0) checkSerial();
  }

  stopAll();
  Serial.println("OK:NO_RESPONSE");
}

void continuousBoth(bool leftFwd, bool rightFwd, int targetDelay) {
  enableAll();
  motorRunning = true;
  lastKeepAlive = millis();
  stopRequested = false;

  digitalWrite(RIGHT_DIR_PIN, leftFwd ? HIGH : LOW);
  digitalWrite(LEFT_DIR_PIN, rightFwd ? HIGH : LOW);

  int currentDelay = PULSE_START;
  int accelStep = 0;
  int decelStep = 0;
  int stepCount = 0;
  bool decelerating = false;

  while (true) {
    if (!decelerating) {
      accelStep++;
      currentDelay = blendDelay((float)accelStep / ACCEL_STEPS, PULSE_START, targetDelay);
    }

    if (stopRequested) decelerating = true;
    if (decelerating) {
      decelStep++;
      currentDelay = blendDelay((float)decelStep / DECEL_STEPS, targetDelay, PULSE_START);
      if (currentDelay >= PULSE_START) break;
    }

    pulseBoth(currentDelay);
    if (++stepCount >= SERIAL_CHECK_INT) {
      stepCount = 0;
      checkSerial();
    }
  }

  motorRunning = false;
  stopAll();
  Serial.println("OK:NO_RESPONSE");
}

void continuousSingle(int stepPin, int dirPin, bool dir, int targetDelay) {
  digitalWrite(dirPin, dir ? HIGH : LOW);
  motorRunning = true;
  lastKeepAlive = millis();
  stopRequested = false;

  int currentDelay = PULSE_START;
  int accelStep = 0;
  int decelStep = 0;
  int stepCount = 0;
  bool decelerating = false;

  while (true) {
    if (!decelerating) {
      accelStep++;
      currentDelay = blendDelay((float)accelStep / ACCEL_STEPS, PULSE_START, targetDelay);
    }

    if (stopRequested) decelerating = true;
    if (decelerating) {
      decelStep++;
      currentDelay = blendDelay((float)decelStep / DECEL_STEPS, targetDelay, PULSE_START);
      if (currentDelay >= PULSE_START) break;
    }

    pulsePin(stepPin, currentDelay);
    if (++stepCount >= SERIAL_CHECK_INT) {
      stepCount = 0;
      checkSerial();
    }
  }

  motorRunning = false;
  stopAll();
  Serial.println("OK:NO_RESPONSE");
}

void continuousDiagonal(bool fwd, bool curveLeft, int targetDelay) {
  enableAll();
  motorRunning = true;
  lastKeepAlive = millis();
  stopRequested = false;

  int outerTarget = targetDelay;
  int innerTarget = (int)(targetDelay / DIAG_RATIO);

  bool leftFwd = fwd;
  bool rightFwd = !fwd;

  digitalWrite(RIGHT_DIR_PIN, leftFwd ? HIGH : LOW);
  digitalWrite(LEFT_DIR_PIN, rightFwd ? HIGH : LOW);

  int outerDelay = PULSE_START;
  int innerDelay = PULSE_START;
  int accelStep = 0;
  int decelStep = 0;
  int stepCount = 0;
  int innerAccumulator = 0;
  bool decelerating = false;

  while (true) {
    if (!decelerating) {
      accelStep++;
      float t = constrain((float)accelStep / ACCEL_STEPS, 0.0f, 1.0f);
      outerDelay = blendDelay(t, PULSE_START, outerTarget);
      innerDelay = blendDelay(t, PULSE_START, innerTarget);
    }

    if (stopRequested) decelerating = true;
    if (decelerating) {
      decelStep++;
      float t = constrain((float)decelStep / DECEL_STEPS, 0.0f, 1.0f);
      outerDelay = blendDelay(t, outerTarget, PULSE_START);
      innerDelay = blendDelay(t, innerTarget, PULSE_START);
      if (outerDelay >= PULSE_START) break;
    }

    innerAccumulator += (int)(DIAG_RATIO * 1000);
    bool stepInner = innerAccumulator >= 1000;
    if (stepInner) innerAccumulator -= 1000;

    if (curveLeft) {
      digitalWrite(RIGHT_STEP_PIN, HIGH);
      if (stepInner) digitalWrite(LEFT_STEP_PIN, HIGH);
      delayMicroseconds(outerDelay);
      digitalWrite(RIGHT_STEP_PIN, LOW);
      digitalWrite(LEFT_STEP_PIN, LOW);
      delayMicroseconds(outerDelay);
    } else {
      digitalWrite(LEFT_STEP_PIN, HIGH);
      if (stepInner) digitalWrite(RIGHT_STEP_PIN, HIGH);
      delayMicroseconds(outerDelay);
      digitalWrite(LEFT_STEP_PIN, LOW);
      digitalWrite(RIGHT_STEP_PIN, LOW);
      delayMicroseconds(outerDelay);
    }

    (void)innerDelay;
    if (++stepCount >= SERIAL_CHECK_INT) {
      stepCount = 0;
      checkSerial();
    }
  }

  motorRunning = false;
  stopAll();
  Serial.println("OK:NO_RESPONSE");
}

void handleCommand(String input) {
  input.trim();
  input.toUpperCase();

  int pulseDelay = speedToDelay(currentSpeed);
  stopRequested = false;
  pendingCmd = "";

  if (input == "PING") {
    Serial.println("DEVICE:MOVE");
    return;
  }

  if (input == "MOVE STOP" || input == "STOP") {
    stopRequested = true;
    motorRunning = false;
    stopAll();
    Serial.println("OK:NO_RESPONSE");
    return;
  }

  if (input == "MOVE PING") {
    lastKeepAlive = millis();
    return;
  }

  if (input.startsWith("MOVE SPEED ")) {
    currentSpeed = constrain(input.substring(11).toInt(), 0, 100);
    Serial.print("OK:SPEED ");
    Serial.println(currentSpeed);
    return;
  }

  String dir = "";
  int steps = 0;

  if (input == "W") {
    dir = "FWD";
  } else if (input == "S") {
    dir = "BACK";
  } else if (input == "A") {
    dir = "LEFT";
  } else if (input == "D") {
    dir = "RIGHT";
  } else if (input.startsWith("MOVE ")) {
    String rest = input.substring(5);
    int spaceIndex = rest.indexOf(' ');
    if (spaceIndex < 0) {
      dir = rest;
    } else {
      dir = rest.substring(0, spaceIndex);
      steps = rest.substring(spaceIndex + 1).toInt();
    }
  } else {
    Serial.println("ERR:UNKNOWN");
    return;
  }

  Serial.println(input);

  if (dir == "FWD") {
    if (steps) fixedBoth(true, false, steps, pulseDelay);
    else continuousBoth(true, false, pulseDelay);
  } else if (dir == "BACK") {
    if (steps) fixedBoth(false, true, steps, pulseDelay);
    else continuousBoth(false, true, pulseDelay);
  } else if (dir == "LEFT") {
    if (steps) {
      enableR();
      fixedSingle(RIGHT_STEP_PIN, RIGHT_DIR_PIN, true, steps, pulseDelay);
    } else {
      enableR();
      continuousSingle(RIGHT_STEP_PIN, RIGHT_DIR_PIN, true, pulseDelay);
    }
  } else if (dir == "RIGHT") {
    if (steps) {
      enableL();
      fixedSingle(LEFT_STEP_PIN, LEFT_DIR_PIN, false, steps, pulseDelay);
    } else {
      enableL();
      continuousSingle(LEFT_STEP_PIN, LEFT_DIR_PIN, false, pulseDelay);
    }
  } else if (dir == "FWD_LEFT") {
    continuousDiagonal(true, true, pulseDelay);
  } else if (dir == "FWD_RIGHT") {
    continuousDiagonal(true, false, pulseDelay);
  } else if (dir == "BACK_LEFT") {
    continuousDiagonal(false, true, pulseDelay);
  } else if (dir == "BACK_RIGHT") {
    continuousDiagonal(false, false, pulseDelay);
  } else if (dir == "CW") {
    if (steps) fixedBoth(true, true, steps, pulseDelay);
    else continuousBoth(true, true, pulseDelay);
  } else if (dir == "CCW") {
    if (steps) fixedBoth(false, false, steps, pulseDelay);
    else continuousBoth(false, false, pulseDelay);
  } else {
    Serial.println("ERR:UNKNOWN_DIR");
  }

  if (pendingCmd.length() > 0) {
    String next = pendingCmd;
    pendingCmd = "";
    handleCommand(next);
  }
}

void setup() {
  Serial.begin(115200);

  pinMode(LEFT_STEP_PIN, OUTPUT);
  pinMode(LEFT_DIR_PIN, OUTPUT);
  pinMode(LEFT_EN_PIN, OUTPUT);
  pinMode(RIGHT_STEP_PIN, OUTPUT);
  pinMode(RIGHT_DIR_PIN, OUTPUT);
  pinMode(RIGHT_EN_PIN, OUTPUT);

  digitalWrite(LEFT_STEP_PIN, LOW);
  digitalWrite(LEFT_DIR_PIN, LOW);
  digitalWrite(RIGHT_STEP_PIN, LOW);
  digitalWrite(RIGHT_DIR_PIN, LOW);

  stopAll();
  Serial.println("DEVICE:MOVE");
  Serial.println("MOVE READY");
}

void loop() {
  if (Serial.available()) {
    cmd = Serial.readStringUntil('\n');
    cmd.trim();
    if (cmd.length() > 0) handleCommand(cmd);
  }
}

// ================================================================
// UzMAX Professional Firmware - ESP32_MOVE
// Dual TMC stepper controller with keydown/keyup keepalive support
//
// Wiring:
//   LEFT  TMC: STEP=GPIO18, DIR=GPIO19, EN=GPIO21
//   RIGHT TMC: STEP=GPIO22, DIR=GPIO23, EN=GPIO25
//
// Dashboard protocol, newline terminated at 115200 baud:
//   PING              -> DEVICE:MOVE
//   MOVE SPEED 60     -> speed percent, 0..100
//   MOVE FWD          -> start continuous forward movement
//   MOVE BACK         -> start continuous backward movement
//   MOVE LEFT         -> start continuous left movement
//   MOVE RIGHT        -> start continuous right movement
//   MOVE PING         -> keepalive while key/button is held
//   MOVE STOP         -> smooth stop and disable drivers
//
// Safety:
//   If MOVE PING is not received for 300 ms while running, the robot stops.
// ================================================================

#include <Arduino.h>

#define DEVICE_NAME "MOVE"

#define LEFT_STEP_PIN   18
#define LEFT_DIR_PIN    19
#define LEFT_EN_PIN     21

#define RIGHT_STEP_PIN  22
#define RIGHT_DIR_PIN   23
#define RIGHT_EN_PIN    25

#define DRIVER_ENABLE_LEVEL  LOW
#define DRIVER_DISABLE_LEVEL HIGH

#define PULSE_SLOW   3000
#define PULSE_FAST    300
#define ACCEL_STEPS   800
#define DECEL_STEPS   800

#define KEEPALIVE_TIMEOUT_MS 300

String queuedCommand = "";
volatile bool stopRequested = false;
int currentSpeed = 60;
unsigned long lastKeepAlive = 0;
bool motorRunning = false;

int speedToPulseDelay(int speed) {
  speed = constrain(speed, 0, 100);
  return map(speed, 0, 100, PULSE_SLOW, PULSE_FAST);
}

void enableLeftDriver() {
  digitalWrite(LEFT_EN_PIN, DRIVER_ENABLE_LEVEL);
}

void disableLeftDriver() {
  digitalWrite(LEFT_EN_PIN, DRIVER_DISABLE_LEVEL);
}

void enableRightDriver() {
  digitalWrite(RIGHT_EN_PIN, DRIVER_ENABLE_LEVEL);
}

void disableRightDriver() {
  digitalWrite(RIGHT_EN_PIN, DRIVER_DISABLE_LEVEL);
}

void enableAllDrivers() {
  enableLeftDriver();
  enableRightDriver();
}

void disableAllDrivers() {
  disableLeftDriver();
  disableRightDriver();
}

int getAccelDelay(int index, int totalSteps, int targetDelay) {
  if (totalSteps > 0 && totalSteps <= ACCEL_STEPS + DECEL_STEPS) return targetDelay;

  if (index < ACCEL_STEPS) {
    float t = (float)index / ACCEL_STEPS;
    float curve = t * t * (3.0f - 2.0f * t);
    return (int)(PULSE_SLOW - curve * (PULSE_SLOW - targetDelay));
  }

  if (totalSteps > 0 && index >= totalSteps - DECEL_STEPS) {
    float t = (float)(totalSteps - index) / DECEL_STEPS;
    float curve = t * t * (3.0f - 2.0f * t);
    return (int)(PULSE_SLOW - curve * (PULSE_SLOW - targetDelay));
  }

  return targetDelay;
}

void checkStop() {
  if (Serial.available()) {
    String incoming = Serial.readStringUntil('\n');
    incoming.trim();
    incoming.toUpperCase();

    if (incoming == "PING") {
      Serial.println("DEVICE:MOVE");
      return;
    }

    if (incoming == "MOVE PING") {
      lastKeepAlive = millis();
      return;
    }

    if (incoming == "MOVE STOP" || incoming == "STOP") {
      stopRequested = true;
      return;
    }

    if (incoming.startsWith("MOVE ") || incoming == "W" || incoming == "A" || incoming == "S" || incoming == "D") {
      stopRequested = true;
      queuedCommand = incoming;
      return;
    }
  }

  if (KEEPALIVE_TIMEOUT_MS > 0 && motorRunning && millis() - lastKeepAlive > KEEPALIVE_TIMEOUT_MS) {
    stopRequested = true;
  }
}

void stepMotorAccel(int stepPin, int dirPin, bool dir, int steps, int targetDelay) {
  digitalWrite(dirPin, dir ? HIGH : LOW);

  for (int i = 0; i < steps; i++) {
    if (stopRequested) return;
    int d = getAccelDelay(i, steps, targetDelay);
    digitalWrite(stepPin, HIGH);
    delayMicroseconds(d);
    digitalWrite(stepPin, LOW);
    delayMicroseconds(d);
    if (i % 50 == 0) checkStop();
  }
}

void stepBothAccel(bool leftFwd, bool rightFwd, int steps, int targetDelay) {
  digitalWrite(RIGHT_DIR_PIN, leftFwd ? HIGH : LOW);
  digitalWrite(LEFT_DIR_PIN, rightFwd ? HIGH : LOW);

  for (int i = 0; i < steps; i++) {
    if (stopRequested) return;
    int d = getAccelDelay(i, steps, targetDelay);
    digitalWrite(RIGHT_STEP_PIN, HIGH);
    digitalWrite(LEFT_STEP_PIN, HIGH);
    delayMicroseconds(d);
    digitalWrite(RIGHT_STEP_PIN, LOW);
    digitalWrite(LEFT_STEP_PIN, LOW);
    delayMicroseconds(d);
    if (i % 50 == 0) checkStop();
  }
}

void continuousBoth(bool leftFwd, bool rightFwd, int targetDelay) {
  enableAllDrivers();
  motorRunning = true;
  lastKeepAlive = millis();

  digitalWrite(RIGHT_DIR_PIN, leftFwd ? HIGH : LOW);
  digitalWrite(LEFT_DIR_PIN, rightFwd ? HIGH : LOW);

  int currentDelay = PULSE_SLOW;
  int stepCount = 0;
  bool decelerating = false;
  int accelStep = 0;
  int decelStep = 0;

  while (true) {
    if (!decelerating && currentDelay > targetDelay) {
      accelStep++;
      float t = constrain((float)accelStep / ACCEL_STEPS, 0.0f, 1.0f);
      float curve = t * t * (3.0f - 2.0f * t);
      currentDelay = (int)(PULSE_SLOW - curve * (PULSE_SLOW - targetDelay));
      if (currentDelay < targetDelay) currentDelay = targetDelay;
    }

    if (stopRequested) decelerating = true;

    if (decelerating) {
      decelStep++;
      float t = constrain((float)decelStep / DECEL_STEPS, 0.0f, 1.0f);
      float curve = 1.0f - t * t * (3.0f - 2.0f * t);
      currentDelay = (int)(targetDelay + curve * (PULSE_SLOW - targetDelay));
      if (currentDelay >= PULSE_SLOW) break;
    }

    digitalWrite(RIGHT_STEP_PIN, HIGH);
    digitalWrite(LEFT_STEP_PIN, HIGH);
    delayMicroseconds(currentDelay);
    digitalWrite(RIGHT_STEP_PIN, LOW);
    digitalWrite(LEFT_STEP_PIN, LOW);
    delayMicroseconds(currentDelay);

    stepCount++;
    if (stepCount >= 50) {
      stepCount = 0;
      checkStop();
    }
  }

  motorRunning = false;
  disableAllDrivers();
  Serial.println("OK:STOP");
}

void continuousSingle(int stepPin, int dirPin, bool dir, int targetDelay) {
  digitalWrite(dirPin, dir ? HIGH : LOW);
  motorRunning = true;
  lastKeepAlive = millis();

  int currentDelay = PULSE_SLOW;
  int stepCount = 0;
  bool decelerating = false;
  int accelStep = 0;
  int decelStep = 0;

  while (true) {
    if (!decelerating && currentDelay > targetDelay) {
      accelStep++;
      float t = constrain((float)accelStep / ACCEL_STEPS, 0.0f, 1.0f);
      float curve = t * t * (3.0f - 2.0f * t);
      currentDelay = (int)(PULSE_SLOW - curve * (PULSE_SLOW - targetDelay));
      if (currentDelay < targetDelay) currentDelay = targetDelay;
    }

    if (stopRequested) decelerating = true;

    if (decelerating) {
      decelStep++;
      float t = constrain((float)decelStep / DECEL_STEPS, 0.0f, 1.0f);
      float curve = 1.0f - t * t * (3.0f - 2.0f * t);
      currentDelay = (int)(targetDelay + curve * (PULSE_SLOW - targetDelay));
      if (currentDelay >= PULSE_SLOW) break;
    }

    digitalWrite(stepPin, HIGH);
    delayMicroseconds(currentDelay);
    digitalWrite(stepPin, LOW);
    delayMicroseconds(currentDelay);

    stepCount++;
    if (stepCount >= 50) {
      stepCount = 0;
      checkStop();
    }
  }

  motorRunning = false;
  disableAllDrivers();
  Serial.println("OK:STOP");
}

void moveLogicalLeft(bool forward, int steps, int pulseDelay) {
  enableRightDriver();
  stepMotorAccel(RIGHT_STEP_PIN, RIGHT_DIR_PIN, forward, steps, pulseDelay);
}

void moveLogicalRight(bool forward, int steps, int pulseDelay) {
  enableLeftDriver();
  stepMotorAccel(LEFT_STEP_PIN, LEFT_DIR_PIN, !forward, steps, pulseDelay);
}

void moveBothLogical(bool leftFwd, bool rightFwd, int steps, int pulseDelay) {
  enableAllDrivers();
  stepBothAccel(leftFwd, rightFwd, steps, pulseDelay);
}

String parseMoveDirection(String input) {
  if (input.startsWith("MOVE ")) {
    String rest = input.substring(5);
    int spaceIndex = rest.indexOf(' ');
    return spaceIndex < 0 ? rest : rest.substring(0, spaceIndex);
  }
  if (input == "W") return "FWD";
  if (input == "S") return "BACK";
  if (input == "A") return "LEFT";
  if (input == "D") return "RIGHT";
  return "";
}

void handleMoveCommand(String input) {
  input.trim();
  input.toUpperCase();

  if (input == "PING") {
    Serial.println("DEVICE:MOVE");
    return;
  }

  if (input == "MOVE PING") {
    lastKeepAlive = millis();
    return;
  }

  if (input == "MOVE STOP" || input == "STOP") {
    stopRequested = true;
    motorRunning = false;
    disableAllDrivers();
    Serial.println("OK:STOP");
    return;
  }

  if (input.startsWith("MOVE SPEED ")) {
    int value = input.substring(11).toInt();
    currentSpeed = constrain(value, 0, 100);
    Serial.print("OK:SPEED ");
    Serial.println(currentSpeed);
    return;
  }

  String direction = parseMoveDirection(input);
  if (direction.length() == 0) {
    Serial.println("ERR:UNKNOWN");
    return;
  }

  int pulseDelay = speedToPulseDelay(currentSpeed);
  stopRequested = false;
  lastKeepAlive = millis();

  if (direction == "FWD") {
    Serial.println("OK:MOVE_FWD");
    continuousBoth(true, false, pulseDelay);
  } else if (direction == "BACK") {
    Serial.println("OK:MOVE_BACK");
    continuousBoth(false, true, pulseDelay);
  } else if (direction == "LEFT") {
    Serial.println("OK:MOVE_LEFT");
    enableRightDriver();
    continuousSingle(RIGHT_STEP_PIN, RIGHT_DIR_PIN, true, pulseDelay);
  } else if (direction == "RIGHT") {
    Serial.println("OK:MOVE_RIGHT");
    enableLeftDriver();
    continuousSingle(LEFT_STEP_PIN, LEFT_DIR_PIN, false, pulseDelay);
  } else if (direction == "CW") {
    Serial.println("OK:MOVE_CW");
    continuousBoth(true, true, pulseDelay);
  } else if (direction == "CCW") {
    Serial.println("OK:MOVE_CCW");
    continuousBoth(false, false, pulseDelay);
  } else {
    Serial.println("ERR:UNKNOWN_DIR");
  }

  if (stopRequested) {
    motorRunning = false;
    disableAllDrivers();
    stopRequested = false;
  }
}

void setup() {
  Serial.begin(115200);

  pinMode(LEFT_STEP_PIN, OUTPUT);
  pinMode(LEFT_DIR_PIN, OUTPUT);
  pinMode(LEFT_EN_PIN, OUTPUT);
  pinMode(RIGHT_STEP_PIN, OUTPUT);
  pinMode(RIGHT_DIR_PIN, OUTPUT);
  pinMode(RIGHT_EN_PIN, OUTPUT);

  digitalWrite(LEFT_STEP_PIN, LOW);
  digitalWrite(LEFT_DIR_PIN, LOW);
  digitalWrite(RIGHT_STEP_PIN, LOW);
  digitalWrite(RIGHT_DIR_PIN, LOW);

  disableAllDrivers();
  Serial.println("DEVICE:MOVE");
  Serial.println("MOVE READY");
}

void loop() {
  if (queuedCommand.length() > 0) {
    String next = queuedCommand;
    queuedCommand = "";
    handleMoveCommand(next);
    return;
  }

  if (Serial.available()) {
    String command = Serial.readStringUntil('\n');
    command.trim();
    if (command.length() > 0) handleMoveCommand(command);
  }
}

// ================================================================
// UzMAX Professional Firmware - ESP32_MOVE
// Dual TMC2208/TMC2209 stepper motor controller
//
// Wiring:
//   LEFT  TMC: STEP=GPIO16, DIR=GPIO17, EN=GPIO5
//   RIGHT TMC: STEP=GPIO18, DIR=GPIO19, EN=GPIO21
//
// Dashboard protocol:
//   PING
//   MOVE FWD 150
//   MOVE BACK 150
//   MOVE LEFT 120
//   MOVE RIGHT 120
//   MOVE STOP
//
// Advanced serial protocol:
//   STATUS
//   LE:<0|1> / RE:<0|1>
//   LMOVE:<steps>,<dir>,<period_us>
//   RMOVE:<steps>,<dir>,<period_us>
//   SYNC:<lsteps>,<rsteps>,<period_us>
//   LSPD:<period_us> / RSPD:<period_us>
//   LDIR:<0|1> / RDIR:<0|1>
//   LSTOP / RSTOP / STOP
//   LRUN / RRUN / RUN
//   LPOS / RPOS
//   LRESET / RRESET
// ================================================================

#include <Arduino.h>

#define DEVICE_NAME "MOVE"

#define L_STEP_PIN 16
#define L_DIR_PIN  17
#define L_EN_PIN   5

#define R_STEP_PIN 18
#define R_DIR_PIN  19
#define R_EN_PIN   21

#define DRIVER_ENABLE_LEVEL LOW
#define DRIVER_DISABLE_LEVEL HIGH

struct MotorState {
  volatile long position = 0;
  volatile long targetSteps = 0;
  volatile long stepsDone = 0;
  bool running = false;
  bool continuous = false;
  uint8_t dir = 0;
  uint32_t stepPeriodUs = 1000;
  bool enabled = false;
  bool stepLevel = false;
  unsigned long lastStepUs = 0;
  uint8_t stepPin;
  uint8_t dirPin;
  uint8_t enPin;
};

MotorState leftM;
MotorState rightM;

uint32_t clampPeriod(uint32_t value) {
  if (value < 120) return 120;
  if (value > 20000) return 20000;
  return value;
}

int clampSpeed(int value) {
  if (value < 0) return 0;
  if (value > 255) return 255;
  return value;
}

uint32_t speedToPeriodUs(int speed) {
  speed = clampSpeed(speed);
  if (speed < 1) speed = 1;
  return map(speed, 1, 255, 2500, 250);
}

void enableMotor(MotorState &m, bool enable) {
  m.enabled = enable;
  digitalWrite(m.enPin, enable ? DRIVER_ENABLE_LEVEL : DRIVER_DISABLE_LEVEL);
}

void setDir(MotorState &m, uint8_t dir) {
  m.dir = dir ? 1 : 0;
  digitalWrite(m.dirPin, m.dir ? HIGH : LOW);
}

void stopMotor(MotorState &m) {
  m.running = false;
  m.continuous = false;
  m.targetSteps = 0;
  m.stepsDone = 0;
  m.stepLevel = false;
  digitalWrite(m.stepPin, LOW);
}

void stopBoth() {
  stopMotor(leftM);
  stopMotor(rightM);
}

void startMove(MotorState &m, long steps, uint8_t dir, uint32_t periodUs) {
  if (steps < 0) steps = -steps;
  m.targetSteps = steps;
  m.stepsDone = 0;
  m.continuous = false;
  m.running = steps > 0;
  m.stepPeriodUs = clampPeriod(periodUs);
  m.stepLevel = false;
  m.lastStepUs = micros();
  setDir(m, dir);
  enableMotor(m, true);
}

void startContinuous(MotorState &m) {
  m.targetSteps = 0;
  m.stepsDone = 0;
  m.continuous = true;
  m.running = true;
  m.stepLevel = false;
  m.lastStepUs = micros();
  enableMotor(m, true);
}

void serviceMotor(MotorState &m) {
  if (!m.running) return;
  unsigned long now = micros();
  if (now - m.lastStepUs < m.stepPeriodUs) return;
  m.lastStepUs = now;
  m.stepLevel = !m.stepLevel;
  digitalWrite(m.stepPin, m.stepLevel ? HIGH : LOW);
  if (!m.stepLevel) {
    m.position += (m.dir == 0) ? 1 : -1;
    if (!m.continuous) {
      m.stepsDone++;
      if (m.stepsDone >= m.targetSteps) stopMotor(m);
    }
  }
}

bool parseLongs(String data, long *out, int count) {
  int idx = 0;
  int start = 0;
  data.trim();
  for (int i = 0; i <= (int)data.length() && idx < count; i++) {
    if (i == (int)data.length() || data[i] == ',') {
      out[idx++] = data.substring(start, i).toInt();
      start = i + 1;
    }
  }
  return idx == count;
}

void printStatus() {
  Serial.printf("LEFT en=%d run=%d cont=%d dir=%d spd=%lu pos=%ld done=%ld target=%ld\n",
    leftM.enabled, leftM.running, leftM.continuous, leftM.dir,
    (unsigned long)leftM.stepPeriodUs, leftM.position, leftM.stepsDone, leftM.targetSteps);
  Serial.printf("RIGHT en=%d run=%d cont=%d dir=%d spd=%lu pos=%ld done=%ld target=%ld\n",
    rightM.enabled, rightM.running, rightM.continuous, rightM.dir,
    (unsigned long)rightM.stepPeriodUs, rightM.position, rightM.stepsDone, rightM.targetSteps);
}

void printHelp() {
  Serial.println("DEVICE:MOVE");
  Serial.println("ESP32 MOVE TMC READY");
  Serial.println("Dashboard: MOVE FWD 150 / MOVE BACK 150 / MOVE LEFT 120 / MOVE RIGHT 120 / MOVE STOP");
  Serial.println("Advanced: STATUS, LMOVE, RMOVE, SYNC, LSPD, RSPD, LDIR, RDIR, RUN, STOP, LPOS, RPOS");
}

void startDashboardMove(String action, int speed) {
  uint32_t period = speedToPeriodUs(speed);
  if (action == "FWD") {
    setDir(leftM, 0);
    setDir(rightM, 0);
  } else if (action == "BACK") {
    setDir(leftM, 1);
    setDir(rightM, 1);
  } else if (action == "LEFT") {
    setDir(leftM, 1);
    setDir(rightM, 0);
  } else if (action == "RIGHT") {
    setDir(leftM, 0);
    setDir(rightM, 1);
  } else {
    Serial.println("ERR:UNKNOWN_MOVE");
    return;
  }
  leftM.stepPeriodUs = period;
  rightM.stepPeriodUs = period;
  startContinuous(leftM);
  startContinuous(rightM);
  Serial.print("OK:");
  Serial.println(action);
}

void handleDashboardMove(String line) {
  if (line == "MOVE STOP") {
    stopBoth();
    Serial.println("OK:STOP");
    return;
  }
  int p1 = line.indexOf(' ');
  int p2 = line.indexOf(' ', p1 + 1);
  if (p1 < 0 || p2 < 0) {
    Serial.println("ERR:MOVE_FORMAT");
    return;
  }
  String action = line.substring(p1 + 1, p2);
  int speed = line.substring(p2 + 1).toInt();
  startDashboardMove(action, speed);
}

void handleCommand(String line) {
  line.trim();
  if (line.length() == 0) return;
  String upper = line;
  upper.toUpperCase();
  if (upper == "PING") {
    Serial.println("DEVICE:MOVE");
  } else if (upper == "HELP") {
    printHelp();
  } else if (upper == "STATUS") {
    printStatus();
  } else if (upper.startsWith("MOVE ")) {
    handleDashboardMove(upper);
  } else if (upper.startsWith("LE:")) {
    enableMotor(leftM, upper.substring(3).toInt() != 0);
    Serial.println("OK:LE");
  } else if (upper.startsWith("RE:")) {
    enableMotor(rightM, upper.substring(3).toInt() != 0);
    Serial.println("OK:RE");
  } else if (upper.startsWith("LMOVE:")) {
    long v[3];
    if (parseLongs(upper.substring(6), v, 3)) {
      startMove(leftM, v[0], (uint8_t)v[1], (uint32_t)v[2]);
      Serial.println("OK:LMOVE");
    } else Serial.println("ERR:LMOVE");
  } else if (upper.startsWith("RMOVE:")) {
    long v[3];
    if (parseLongs(upper.substring(6), v, 3)) {
      startMove(rightM, v[0], (uint8_t)v[1], (uint32_t)v[2]);
      Serial.println("OK:RMOVE");
    } else Serial.println("ERR:RMOVE");
  } else if (upper.startsWith("SYNC:")) {
    long v[3];
    if (parseLongs(upper.substring(5), v, 3)) {
      startMove(leftM, v[0], leftM.dir, (uint32_t)v[2]);
      startMove(rightM, v[1], rightM.dir, (uint32_t)v[2]);
      Serial.println("OK:SYNC");
    } else Serial.println("ERR:SYNC");
  } else if (upper.startsWith("LSPD:")) {
    leftM.stepPeriodUs = clampPeriod((uint32_t)upper.substring(5).toInt());
    Serial.println("OK:LSPD");
  } else if (upper.startsWith("RSPD:")) {
    rightM.stepPeriodUs = clampPeriod((uint32_t)upper.substring(5).toInt());
    Serial.println("OK:RSPD");
  } else if (upper.startsWith("LDIR:")) {
    setDir(leftM, (uint8_t)upper.substring(5).toInt());
    Serial.println("OK:LDIR");
  } else if (upper.startsWith("RDIR:")) {
    setDir(rightM, (uint8_t)upper.substring(5).toInt());
    Serial.println("OK:RDIR");
  } else if (upper == "LSTOP") {
    stopMotor(leftM);
    Serial.println("OK:LSTOP");
  } else if (upper == "RSTOP") {
    stopMotor(rightM);
    Serial.println("OK:RSTOP");
  } else if (upper == "STOP") {
    stopBoth();
    Serial.println("OK:STOP");
  } else if (upper == "LRUN") {
    startContinuous(leftM);
    Serial.println("OK:LRUN");
  } else if (upper == "RRUN") {
    startContinuous(rightM);
    Serial.println("OK:RRUN");
  } else if (upper == "RUN") {
    startContinuous(leftM);
    startContinuous(rightM);
    Serial.println("OK:RUN");
  } else if (upper == "LPOS") {
    Serial.printf("LPOS:%ld\n", leftM.position);
  } else if (upper == "RPOS") {
    Serial.printf("RPOS:%ld\n", rightM.position);
  } else if (upper == "LRESET") {
    leftM.position = 0;
    Serial.println("OK:LRESET");
  } else if (upper == "RRESET") {
    rightM.position = 0;
    Serial.println("OK:RRESET");
  } else {
    Serial.print("ERR:UNKNOWN:");
    Serial.println(line);
  }
}

void setup() {
  Serial.begin(115200);
  leftM.stepPin = L_STEP_PIN;
  leftM.dirPin = L_DIR_PIN;
  leftM.enPin = L_EN_PIN;
  rightM.stepPin = R_STEP_PIN;
  rightM.dirPin = R_DIR_PIN;
  rightM.enPin = R_EN_PIN;
  pinMode(L_STEP_PIN, OUTPUT);
  pinMode(L_DIR_PIN, OUTPUT);
  pinMode(L_EN_PIN, OUTPUT);
  pinMode(R_STEP_PIN, OUTPUT);
  pinMode(R_DIR_PIN, OUTPUT);
  pinMode(R_EN_PIN, OUTPUT);
  digitalWrite(L_STEP_PIN, LOW);
  digitalWrite(R_STEP_PIN, LOW);
  digitalWrite(L_DIR_PIN, LOW);
  digitalWrite(R_DIR_PIN, LOW);
  enableMotor(leftM, false);
  enableMotor(rightM, false);
  printHelp();
}

void loop() {
  serviceMotor(leftM);
  serviceMotor(rightM);
  if (Serial.available()) {
    String line = Serial.readStringUntil('\n');
    handleCommand(line);
  }
}
